package org.eclipse.rdf4j.workbench.proxy;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.concurrent.atomic.AtomicBoolean;

import org.eclipse.rdf4j.workbench.support.TestFilterConfig;
import org.junit.jupiter.api.Test;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;

import jakarta.servlet.FilterChain;

class RedirectFilterTest {

	@Test
	void doFilterRedirectsMatchingServletAndPathInfoTargets() throws Exception {
		RedirectFilter filter = new RedirectFilter();
		filter.init(TestFilterConfig.withParams("redirect", "/old", "/new", "/path", "/target"));

		MockHttpServletRequest servletPathRequest = new MockHttpServletRequest("GET", "/ctx/old");
		servletPathRequest.setContextPath("/ctx");
		servletPathRequest.setServletPath("/old");
		MockHttpServletResponse servletPathResponse = new MockHttpServletResponse();
		filter.doFilter(servletPathRequest, servletPathResponse, passthrough());
		assertThat(servletPathResponse.getRedirectedUrl()).isEqualTo("/ctx/new");

		MockHttpServletRequest pathInfoRequest = new MockHttpServletRequest("GET", "/path");
		pathInfoRequest.setContextPath(null);
		pathInfoRequest.setPathInfo("/path");
		MockHttpServletResponse pathInfoResponse = new MockHttpServletResponse();
		filter.doFilter(pathInfoRequest, pathInfoResponse, passthrough());
		assertThat(pathInfoResponse.getRedirectedUrl()).isEqualTo("/target");

		filter.destroy();
	}

	@Test
	void doFilterPassesThroughNonMatchingRequests() throws Exception {
		RedirectFilter filter = new RedirectFilter();
		filter.init(TestFilterConfig.withParams("redirect", "/old", "/new"));

		AtomicBoolean invoked = new AtomicBoolean();
		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/ctx/other");
		request.setContextPath("/ctx");
		request.setServletPath("/other");
		MockHttpServletResponse response = new MockHttpServletResponse();

		filter.doFilter(request, response, (req, resp) -> invoked.set(true));

		assertThat(invoked).isTrue();
		assertThat(response.getRedirectedUrl()).isNull();
	}

	private static FilterChain passthrough() {
		return (req, resp) -> {
		};
	}
}
